-- -------------------------------------------------------
-- 3. Asociar productos a su categoría-marca
--    INSERT IGNORE es idempotente (no duplica relaciones)
-- -------------------------------------------------------
-- [1/4971] ref=8435265309940 -> marca=Idempet
INSERT IGNORE INTO llx_categorie_product (fk_categorie, fk_product)
SELECT cat.rowid, p.rowid
FROM   llx_categorie cat
JOIN   llx_product   p   ON p.ref = '8435265309940'
WHERE  cat.label = 'Idempet'
  AND  cat.type = 0
  AND  cat.fk_parent = (
       SELECT c2.rowid FROM llx_categorie c2
       WHERE c2.label = 'Marcas' AND c2.type = 0 AND c2.fk_parent = 0
  );
