  AND  cat.type = 0
  AND  cat.fk_parent = (
       SELECT c2.rowid FROM llx_categorie c2
       WHERE c2.label = 'Marcas' AND c2.type = 0 AND c2.fk_parent = 0
  );

COMMIT;
